function executeSkill(context) {
  const sourcePiece = context.piece;
  const damageValue = sourcePiece.attack * context.skill.powerMultiplier;
  const targetPosition = selectTarget({ type: 'grid', range: 10, filter: 'all' });
  if (!targetPosition || targetPosition.needsTargetSelection) {
    return targetPosition;
  }
  const statusId = 'blizzard-' + Date.now();
  // 把暴风雪数据存为玩家 statusTag
  addPlayerStatusEffectById(sourcePiece.ownerPlayerId, {
    id: statusId,
    type: 'blizzard',
    centerX: targetPosition.x,
    centerY: targetPosition.y,
    damage: damageValue
  });
  // 绑定触发规则到玩家
  addPlayerRuleById(sourcePiece.ownerPlayerId, 'rule-blizzard-active');
  // 绑定效果技能到玩家
  addPlayerSkillById(sourcePiece.ownerPlayerId, 'blizzard-damage');
  // 视觉：tileEffect 高亮
  if (!battle.extensions) battle.extensions = {};
  if (!battle.extensions.tileEffects) battle.extensions.tileEffects = [];
  var blizzardRadius = 3;
  for (var bx = targetPosition.x - blizzardRadius; bx <= targetPosition.x + blizzardRadius; bx++) {
    for (var by = targetPosition.y - blizzardRadius; by <= targetPosition.y + blizzardRadius; by++) {
      battle.extensions.tileEffects.push({ x: bx, y: by, sourceId: statusId, tileType: 'blizzard', icon: '❄️', bgColor: 'rgba(96, 165, 250, 0.4)', boxShadow: 'inset 0 0 4px rgba(147, 197, 253, 0.6)', iconPosition: 'top-right' });
    }
  }
  return {
    message: sourcePiece.name + '使用了暴风雪，在(' + targetPosition.x + ',' + targetPosition.y + ')创造了暴风雪区域，将在对方回合结束时对7x7格范围内的敌人造成' + damageValue + '点伤害并使其冰冻',
    success: true
  };
}

