function calculatePreview(piece, skillDef) {
  const damageValue = Math.round(piece.attack * skillDef.powerMultiplier);
  return {
    description: '选择全局任意位置，创造7*7格的暴风雪区域，对方回合结束时对其中所有敌人造成' + damageValue + '点伤害（相当于攻击力150%）和1回合冰冻',
    expectedValues: { damage: damageValue }
  };
}
